class Solution {
public:
    int firstBadVersion(int n) {
        long long left = 1, right = n;
        while (left < right) {
            long long mid = left + (right - left) / 2;
            if (isBadVersion(mid)) {
                right = mid;
            } else {
                left = mid + 1;
            }
        }
        return static_cast<int>(left);
    }
};
